import BrandGallery from "./BrandGallery";
import { PHOTOS } from "../data/photos";

const eventPhotos = PHOTOS.filter((photo) => ["engagement", "naming"].includes(photo.category)).slice(0, 9);

export default function AyyanEventGallery({ onBack }) {
  return (
    <BrandGallery
      title="Ayyan Events"
      subtitle="Grand ceremonies, ring celebrations and naming rituals brought to life with cinematic storytelling."
      photos={eventPhotos}
      onBack={onBack}
    />
  );
}
